function getDuration(trada){
 if(trada){
  track_=trada;
  tracks=track_.split('MTrk');
  duration = 0;
  currentTempo = 0;
  t = 0;
  track = tracks[1];
  mce = track.split('\n');
  mc=track.length;
  header = track_.split(' ');
  timebase = parseInt(header[3]);
  f = 1 / timebase/ 1000000;
  t=0;
  for (i=0;i<mce.length;i++){
   mml=mce[i];
   msg = mml.split(' ');
   if (msg[1]=='Tempo'){
    dt = parseInt(msg[0]) - t;
    duration += dt * currentTempo * f;
    t = parseInt(msg[0]);
    currentTempo = parseInt(msg[2]);
    }
   }
  end_time = t;
  for(i=0;i<tracks.length;i++){
   tr_=tracks[i];
   sdgg=tr_.split('\n');
   endti=0;
   for(a=0;a<sdgg.length;a++){
    aaa=sdgg[a];
    fdgh=aaa.split(' ');
    if(fdgh.length>1){
     endti=parseInt(fdgh[0]);
     if(!isNaN(endti )){
      end_time=Math.max(end_time, endti);
      }
     }
    }
   }
  if (end_time>t){
   dt = end_time - t;
   duration += dt * currentTempo * f;
   }
  if(genre=='punk'){
   return (duration/2);
   }
  else{
   return duration;
   }
  }
 else{
  return 0;
  }
 }
