  function _writeVarLenje(value){
   buf = value & 0x7F;
   str='';
   while ((value >>= 7)){
    buf <<= 8;
    buf |= ((value & 0x7F) | 0x80);
    }
   while (1==1){
    fdg=''+ConvertBase.dec2hex(buf%256);
    sfgg=fdg;
    if(fdg.length==1){
     sfgg='0'+fdg;
     }
    str=str+sfgg.toUpperCase()+' ';
    if (buf & 0x80) buf >>= 8;
    else break;
    }
   return str;
   }
