 function makeDeps(ars33, mska, min_, max_, ch, vv88, gnr){
  min=Math.min(min_, max_);
  max=Math.max(min_, max_);
  arrc=new Array(max-min);
  barrc=new Array(max-min);
  barrs=new Array(max-min);
  for(i=min;i<max;i++){
   ars=ars33[Math.floor(i/max*ars33.length)];
   arrc[i]=0;
   barrs[i]='';
   if(i<ars.length){
    if(ars[i][0]==true){
     barrc[i]=true;
     }
    else{
     barrc[i]=false;
     }
    }
   else{
    barrc[i]=false;
    }
   }
  for(i=min;i<max;i++){
   ars=ars33[Math.floor(i/max*ars33.length)];
   if(mska[i]   ){
    u=0;
    dd=ars[i];
    ff=ars[i][0];
    t=1;
    barrs[i]='0';
    b=0;
    while(u<dd.length){
     ars=ars33[Math.floor(u/dd.length*ars33.length)];
     gg=ars[i][u];
     if(gg==ff ){
      if(gnr=='cyber' && (ch==7 || ch==8)){
       if(gg==true){
        u+=30;
        t+=30;
        }
       else{
        u++;
        t++;
        }
       }
      else{
       u++;
       t++;
       }
      }
     else{
      b=u;
      barrs[i]=barrs[i]+' '+(b-0)+' '+ff+'-'+(b+1) +' ';
      ff=!ff;
      }
     }
    barrs[i]=barrs[i]+(dd.length)+' '+ff;
    }
   else{
    barrs[i]='';
    }
   }
  return barrs;
  }
